router = APIRouter()


def _parse_triage_output(
    content: str,
) -> tuple[Literal["false_positive", "likely_real", "needs_review"], float, str, str | None]:
    """Parse model output into normalized triage fields."""
    verdict = "needs_review"
    confidence = 0.5
    rationale = content.strip()[:1200] or "Sin detalle."
    suggested_state: str | None = None

    try:
        data = json.loads(content)
        if isinstance(data, dict):
            raw_verdict = str(data.get("verdict", "")).strip().lower()
            if raw_verdict in {"false_positive", "likely_real", "needs_review"}:
                verdict = raw_verdict
            raw_conf = data.get("confidence")
            if isinstance(raw_conf, (int, float)):
                confidence = max(0.0, min(1.0, float(raw_conf)))
            raw_rationale = data.get("rationale")
            if isinstance(raw_rationale, str) and raw_rationale.strip():
                rationale = raw_rationale.strip()[:1200]
            raw_state = data.get("suggested_state")
            if isinstance(raw_state, str) and raw_state.strip():
                suggested_state = raw_state.strip()[:128]
            return verdict, confidence, rationale, suggested_state
    except json.JSONDecodeError:
        pass

    lowered = content.lower()
    if "false_positive" in lowered or "falso positivo" in lowered:
        verdict = "false_positive"
    elif "likely_real" in lowered or "real vulnerability" in lowered:
        verdict = "likely_real"
    return verdict, confidence, rationale, suggested_state


@router.get("/export.csv")
async def export_vulnerabilidades_csv(
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(get_current_user),
):
    """Exporta hallazgos del usuario a CSV; deja huella en auditoría (A7)."""
    items = await vulnerabilidad_svc.list(db, filters={"user_id": current_user.id})
    buf = StringIO()
    writer = csv.writer(buf)
    writer.writerow(
        [
            "id",
            "titulo",
            "fuente",
            "severidad",
            "estado",
            "cwe_id",
            "owasp_categoria",
            "fecha_limite_sla",
        ]
    )
    for v in items:
        writer.writerow(
            [
                str(v.id),
                v.titulo,
                v.fuente,
                v.severidad,
                v.estado,
                v.cwe_id or "",
                v.owasp_categoria or "",
                v.fecha_limite_sla.isoformat() if v.fecha_limite_sla else "",
            ]
        )
    body = buf.getvalue()
    digest = hashlib.sha256(body.encode("utf-8")).hexdigest()
    await audit_record(
        db,
        action="vulnerabilidad.export_csv",
        entity_type="vulnerabilidad",
        entity_id=current_user.id,
        metadata={
            "rows": len(items),
            "sha256": digest,
            "format": "csv",
        },
    )
    return Response(
        content=body,
        media_type="text/csv; charset=utf-8",
        headers={
            "Content-Disposition": 'attachment; filename="vulnerabilidades.csv"',
        },
    )


@router.get("")
async def list_vulnerabilidads(
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(get_current_user),
    page: int = 1,
    page_size: int = 50,
):
    """List vulnerabilidads owned by the current user (paginated)."""
    from sqlalchemy import func, select

    from app.core.response import paginated

    # Enforce pagination limits (S4: Rate limiting)
    page = max(1, page)
    page_size = min(max(1, page_size), 100)  # Cap at 100

    # Get paginated items
    stmt = select(Vulnerabilidad).where(
        Vulnerabilidad.user_id == current_user.id,
        Vulnerabilidad.deleted_at.is_(None),
    ).order_by(Vulnerabilidad.created_at.desc())

    # Apply pagination
    stmt = stmt.offset((page - 1) * page_size).limit(page_size)
    result = await db.execute(stmt)
    items = result.scalars().all()

    # Get total count
    count_stmt = select(func.count(Vulnerabilidad.id)).where(
        Vulnerabilidad.user_id == current_user.id,
        Vulnerabilidad.deleted_at.is_(None),
    )
    total_result = await db.execute(count_stmt)
    total = total_result.scalar_one_or_none() or 0

    return paginated(
        [VulnerabilidadRead.model_validate(x).model_dump(mode="json") for x in items],
        page=page,
        page_size=page_size,
        total=total,
    )


@router.get("/{id}")
async def get_vulnerabilidad(
    id: str,
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(get_current_user),
):
    """Get a single owned vulnerabilidad by ID (404 if not owned)."""
    # Validate UUID format
    try:
        entity_id = UUID(id)
    except (ValueError, TypeError) as e:
        raise NotFoundException(f"Invalid ID format: {id}") from e

    # Fetch entity
    entity = await vulnerabilidad_svc.get(db, entity_id, scope={"user_id": current_user.id})
    if not entity or entity.user_id != current_user.id:
        raise NotFoundException(f"Vulnerabilidad {id} not found")

    return success(VulnerabilidadRead.model_validate(entity).model_dump(mode="json"))


@router.post("", status_code=201)
async def create_vulnerabilidad(
    entity_in: VulnerabilidadCreate,
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(get_current_user),
):
    """Create a new vulnerabilidad for the current user."""
    entity = await vulnerabilidad_svc.create(db, entity_in, extra={"user_id": current_user.id})
    return success(VulnerabilidadRead.model_validate(entity).model_dump(mode="json"))


@router.post("/{id}/ia/triage-fp")
async def triage_vulnerabilidad_false_positive(
    id: UUID,
    payload: VulnerabilidadIATriageRequest,
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(require_permission(P.IA.EXECUTE)),
):
    """IA-assisted triage for potential false positives."""
    vuln = await vulnerabilidad_svc.get(db, id, scope={"user_id": current_user.id})
    if vuln is None:
        raise NotFoundException("Vulnerabilidad not found")

    motor_hints = get_motor_triage_hints(vuln.fuente)
    prompt = (
        "Eres un analista AppSec. Evalúa si el hallazgo podría ser falso positivo.\n"
        f"Titulo: {vuln.titulo}\n"
        f"Descripcion: {vuln.descripcion or 'N/A'}\n"
        f"Fuente (motor): {vuln.fuente}\n"
        f"Guía específica para este motor: {motor_hints}\n"
        f"Severidad: {vuln.severidad}\n"
        f"Estado: {vuln.estado}\n"
        f"CVSS: {vuln.cvss_score if vuln.cvss_score is not None else 'N/A'}\n"
        f"CWE: {vuln.cwe_id or 'N/A'}\n"
        f"OWASP: {vuln.owasp_categoria or 'N/A'}\n"
        f"Contexto adicional: {payload.contexto_adicional or 'N/A'}\n\n"
        "Responde SOLO JSON con campos: "
        '{"verdict":"false_positive|likely_real|needs_review","confidence":0.0,"rationale":"...","suggested_state":"..."}'
    )
    result = await run_prompt(db, prompt=prompt, dry_run=payload.dry_run)
    verdict, confidence, rationale, suggested_state = _parse_triage_output(result.content)

    await audit_record(
        db,
        action="vulnerabilidad.ia_triage_fp",
        entity_type="vulnerabilidad",
        entity_id=vuln.id,
        metadata={
            "provider": result.provider,
            "model": result.model,
            "dry_run": payload.dry_run,
            "fuente": vuln.fuente,
            "verdict": verdict,
            "confidence": confidence,
        },
    )
    response = VulnerabilidadIATriageRead(
        provider=result.provider,
        model=result.model,
        dry_run=payload.dry_run,
        verdict=verdict,
        confidence=confidence,
        rationale=rationale,
        suggested_state=suggested_state,
        raw_content=result.content,
    )
    return success(response.model_dump())


@router.patch("/{id}")
async def update_vulnerabilidad(
    entity_in: VulnerabilidadUpdate,
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(get_current_user),
    entity: Vulnerabilidad = Depends(require_ownership(vulnerabilidad_svc)),
):
    """Partially update an owned vulnerabilidad (404 if not owned)."""
    updated = await vulnerabilidad_svc.update(
        db, entity.id, entity_in, scope={"user_id": current_user.id}
    )
    return success(VulnerabilidadRead.model_validate(updated).model_dump(mode="json"))


@router.delete("/{id}")
async def delete_vulnerabilidad(
    db: AsyncSession = Depends(get_db),
    current_user: User = Depends(get_current_user),
    entity: Vulnerabilidad = Depends(require_ownership(vulnerabilidad_svc)),
):
    """Delete an owned vulnerabilidad (404 if not owned)."""
    await vulnerabilidad_svc.delete(db, entity.id, scope={"user_id": current_user.id})
    return success(None, meta={"message": "Vulnerabilidad deleted"})
